```js
// Middleware 404 pour les routes non trouvées
app.use((req, res, next) => {
  res.status(404).json({ error: 'Route non trouvée' });
});

// Middleware de gestion d’erreurs (après toutes les routes)
app.use((err, req, res, next) => {
  const status = err.status || 500;
  if (process.env.NODE_ENV === 'development') {
    return res.status(status).json({
      error: err.message,
      stack: err.stack
    });
  }
  // production
  res.status(status).json({ error: 'Erreur interne du serveur' });
});
```

```js
const fs = require('fs');
const path = require('path');
const logFile = path.join(__dirname, 'error.log');

const logErrorMiddleware = (err, req, res, next) => {
  const logEntry = `${new Date().toISOString()} - ${req.method} ${req.originalUrl} - ${err.message}\n`;
  fs.appendFile(logFile, logEntry, (err) => {
    if (err) console.error('Erreur lors de l\'écriture du log', err);
  });
  next(err); // on transmet l'erreur au prochain middleware
};

// Placer ce middleware avant le dernier qui envoie la réponse
```

Avant :
```js
app.get('/data', async (req, res) => {
  const data = await db.query('SELECT ...'); // erreur possible
  res.json(data);
});
```
Après installation (`npm install express-async-errors`) et ajout en haut du fichier principal :
```js
require('express-async-errors');
// les routes restent identiques, mais les erreurs asynchrones sont automatiquement passées à next(err)
```
